param([string]$OllamaUrl = "http://localhost:11434", [string]$Model = "qwen2.5:7b", [string]$Root = (Resolve-Path "$PSScriptRoot\..").Path, [string]$SeedFile = "$Root\Seed\seed_idea.txt", [string]$StateFile = "$Root\state.json", [string]$KillFile = "$Root\stop.txt")
function Write-RefinementLog($m) { $log = "$Root\Logs\refinement.log"; if (!(Test-Path (Split-Path $log))) { New-Item -ItemType Directory -Force -Path (Split-Path $log) | Out-Null }; Add-Content $log "$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss') | $m" }
function Invoke-OllamaCompletion($prompt, $timeout=240) { $uri = "$OllamaUrl/api/generate"; $body = @{model=$Model; prompt=$prompt; stream=$false} | ConvertTo-Json -Compress; $attempt=0; while ($true) { $attempt++; try { $r = Invoke-RestMethod -Uri $uri -Method Post -Body $body -ContentType "application/json" -TimeoutSec $timeout; if ($r.response) { Write-RefinementLog "OK attempt $attempt"; return $r.response } } catch { Write-RefinementLog "Fail attempt $attempt: $_"; if ($attempt -ge 3) { return "[ERROR] $_" }; Start-Sleep 5 } } }
